import json
import subprocess
from google.cloud import storage

def main(event, context):
    # Extract filename and conversion options from event metadata
    filename = event['name']
    conversion_options = event['metadata']['conversion_options']

    # Run convert command using subprocess.call() with event parameters
    subprocess.call(['convert', '-quality', '80', filename, '-resize', '200x200', '-gravity', 'center', '-crop', '200x200+0+0', '-format', 'png', filename])

    # Upload converted image to Cloud Storage
    storage_client = storage.Client()
    bucket = storage_client.get_bucket('my-image-bucket')
    blob = bucket.blob(filename)
    blob.upload_from_string(open(filename, 'rb').read())